import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { HIRFamilyStatDateController } from "./HIRFamilyStatDateController";
import { HIRFamilyYearlyPayments } from "./HIRFamilyYearlyPayments";
import { Grid } from '@material-ui/core';
import { HIRFamilyYearlyAppointments } from './HIRFamilyYearlyAppointments/HIRFamilyYearlyAppointments';


const style = theme => ({
    root: {
        marginTop : 20,
        marginBottom : 20,
    }
})
class _HIRFamilyStatistics extends Component {
    render() {
        const {classes, familyId, members, memberIds} = this.props;
        return (
            <div className={classes.root}>
                <Grid container spacing={2}>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        <HIRFamilyStatDateController
                            familyId={familyId}
                            members={members}
                            memberIds={memberIds}
                            component={HIRFamilyYearlyPayments}/>
                    </Grid>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        <HIRFamilyStatDateController
                            familyId={familyId}
                            members={members}
                            memberIds={memberIds}
                            component={HIRFamilyYearlyAppointments}/>
                    </Grid>
                </Grid>

            </div>
        );
    }
}


_HIRFamilyStatistics.propTypes = {
    classes : PropTypes.object.isRequired,
    members : PropTypes.array,
    memberIds : PropTypes.array,
    familyId : PropTypes.number,
};
export const HIRFamilyStatistics = connect()(withStyles(style)(_HIRFamilyStatistics));
export {HIRFamilyStatistics as default}