import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { IconButton, TextField } from '@material-ui/core';
import { ArrowBackIos, ArrowForwardIos } from '@material-ui/icons';
import { hirUtil } from '../../../../utils';
const style = theme => ({
    root: {
        
    },
    container : {
        display : "flex",
        justifyContent : "center",
        alignItems : "center",
    },
    icon : {
        color : hirUtil.getTheme().primary1
    },
    text : {
        textAlign : "center",
    }
})
class _HIRFamilyStatDateController extends Component {
    state = {
        year : new Date().getFullYear(),
        memberIds : null
    }
    componentDidMount() {
        const {year} = this.state;
        this.getComponentData(year);
    }    
    // static getDerivedStateFromProps(props, state) {
    //     const {memberIds} = props;
    //     if(!state.memberIds || JSON.stringify(state.memberIds) !== JSON.stringify(memberIds)){
    //         state.memberIds = memberIds;
    //     }
    // }
    nextBtn(){
        let year = parseInt(this.state.year) + 1;
        this.setState({year});
        this.getComponentData(year);
    }
    prevBtn(){
        let year = parseInt(this.state.year) - 1;
        this.setState({year});
        this.getComponentData(year);
    }
    onChange(e){
        const year = parseInt(e.target.value);
        this.setState({year});
        this.getComponentData(year);
    }
    async getComponentData(year){
        const {component, memberIds, dispatch} = this.props;
        if(memberIds){
            const data = await component.getData(memberIds, year, dispatch);
            this.setState({data});
        }
    }
    async handleMemberIdChanges(){
        const { memberIds} = this.props;
        if(!this.state.memberIds || JSON.stringify(this.state.memberIds) !== JSON.stringify(memberIds)){
            if(memberIds){
                await this.getComponentData(this.state.year);
                this.state.memberIds = [...memberIds];
            }
        }
    }
    render() {
        const {classes, component : Component, members, memberIds} = this.props;
        const {year, data} = this.state;
        this.handleMemberIdChanges();
        return (
            <div className={classes.root}>
                <div className={classes.container}>
                    <IconButton onClick={this.prevBtn.bind(this)}>
                        <ArrowBackIos fontSize="small" className={classes.icon}/>
                    </IconButton>
                    <TextField
                        margin="normal"
                        variant="outlined"
                        value={year}
                        inputProps={{
                            className :classes.text
                        }}
                        onChange={this.onChange.bind(this)}
                        label="Year"
                        placeholder="Year"/>
                    <IconButton onClick={this.nextBtn.bind(this)}>
                        <ArrowForwardIos fontSize="small" className={classes.icon}/>
                    </IconButton>
                </div>
                <Component
                    data={data}
                    members={members}
                    year={year}/>
            </div>
        );
    }
}
_HIRFamilyStatDateController.propTypes = {
    classes : PropTypes.object.isRequired,
    component : PropTypes.object,
    familyId : PropTypes.number,
    members : PropTypes.array,
    memberIds : PropTypes.array,
};
export const HIRFamilyStatDateController = withStyles(style)(_HIRFamilyStatDateController);